// Process PDF analysis result and preserve binary data
const input = $input.first();
const originalBinary = $('analyze-pdf-type').first().binary;
const originalJson = $('analyze-pdf-type').first().json;

// Default values if analysis failed
let pdfType = 'image';
let needsOcr = true;
let textLength = 0;
let analysisError = null;

// Check if analysis was successful
if (input.json && input.json.pdf_type) {
  pdfType = input.json.pdf_type;
  needsOcr = input.json.needs_ocr || false;
  textLength = input.json.text_length || 0;
} else if (input.json && input.json.error) {
  analysisError = input.json.error;
} else {
  analysisError = 'PDF analysis service unavailable';
}

// Return result with preserved binary data
return {
  json: {
    ...originalJson, // Preserve original JSON data
    pdf_analysis: {
      type: pdfType,
      extractable_text_length: textLength,
      needs_ocr: needsOcr,
      analysis_timestamp: new Date().toISOString(),
      analysis_error: analysisError
    }
  },
  binary: originalBinary // Preserve original binary data
};

