// Normalize and combine results from both paths
const input = $input.first().json;
const originalData = $('process-analysis-result').first().json;

// Determine processing path and extract relevant data
let extractedText = '';
let processingMethod = '';
let confidence = 1.0;
let processingTime = 0;
let engineUsed = 'unknown';

// Check if this came from OCR or direct text extraction
if (input.confidence_score !== undefined) {
  // OCR path
  extractedText = input.text || input.extracted_text || '';
  processingMethod = 'ocr_processing';
  confidence = input.confidence_score || 0;
  processingTime = input.processing_time || 0;
  engineUsed = input.engine_used || 'trocr';
} else if (input.text) {
  // Direct text extraction path
  extractedText = input.text;
  processingMethod = 'direct_text_extraction';
  confidence = 1.0;
  processingTime = 0.1;
  engineUsed = 'extract_from_file';
} else {
  // Fallback - no text found
  extractedText = '';
  processingMethod = 'no_text_found';
  confidence = 0;
  processingTime = 0;
  engineUsed = 'none';
}

// Get Ollama response
const ollamaResponse = input.response || '';

try {
  // Try to parse JSON from Ollama response
  let extractedData;

  // Clean response - remove markdown code blocks if present
  const cleanResponse = ollamaResponse
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .trim();

  try {
    extractedData = JSON.parse(cleanResponse);
  } catch (parseError) {
    // If JSON parsing fails, try to extract JSON from text
    const jsonMatch = cleanResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      extractedData = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('No valid JSON found in response');
    }
  }

  // Build final result
  const result = {
    // Preserve original data (filename, etc.)
    ...originalData,
    // Update with extracted text
    text: extractedText,
    // Add structured invoice data
    extracted_invoice_data: extractedData,
    // Add processing metadata
    processing_metadata: {
      pdf_type: originalData.pdf_analysis?.type || 'unknown',
      method: processingMethod,
      confidence_score: confidence,
      processing_time_seconds: processingTime,
      engine_used: engineUsed,
      extraction_model: 'llama3.2:latest',
      timestamp: new Date().toISOString(),
      original_analysis: originalData.pdf_analysis
    }
  };

  return { json: result };

} catch (error) {
  // Return error response but preserve original data
  return {
    json: {
      ...originalData,
      text: extractedText,
      extracted_invoice_data: null,
      processing_metadata: {
        pdf_type: originalData.pdf_analysis?.type || 'unknown',
        method: processingMethod,
        confidence_score: confidence,
        error: error.message,
        raw_response: ollamaResponse,
        timestamp: new Date().toISOString(),
        original_analysis: originalData.pdf_analysis
      }
    }
  };
}
